import React from "react";
import ReactDOM from "react-dom/client";
import {
  createBrowserRouter,
  RouterProvider,
  useLoaderData,
  useSearchParams,
} from "react-router-dom";
import "./index.css";

// types

type Province = {
  id: number;
  name: string;
};

type Regency = {
  id: number;
  name: string;
  province_id: number;
};

type District = {
  id: number;
  name: string;
  regency_id: number;
};

type RegionsData = {
  provinces: Province[];
  regencies: Regency[];
  districts: District[];
};

type SelectProps = {
  icon: React.ReactNode;
  value: string;
  onChange: (e: React.ChangeEvent<HTMLSelectElement>) => void;
  disabled?: boolean;
  placeholder: string;
  options: { id: number; name: string }[];
};

// fetch data
async function loader(): Promise<RegionsData> {
  const res = await fetch("/data/indonesia_regions.json");

  if (!res.ok) {
    throw new Error("Failed to fetch regions data");
  }

  return res.json();
}

