function ChevronDownIcon() {
  return (
    <svg
      width="14"
      height="14"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <polyline points="6 9 12 15 18 9" />
    </svg>
  );
}

function ArrowDownIcon() {
  return (
    <svg
      width="16"
      height="16"
      viewBox="0 0 24 24"
      fill="none"
      stroke="#9ca3af"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <line x1="12" y1="5" x2="12" y2="19" />
      <polyline points="19 12 12 19 5 12" />
    </svg>
  );
}

function ChevronRightIcon() {
  return (
    <svg
      width="12"
      height="12"
      viewBox="0 0 24 24"
      fill="none"
      stroke="#9ca3af"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <polyline points="9 18 15 12 9 6" />
    </svg>
  );
}

// select component

function StyledSelect({
  icon,
  value,
  onChange,
  disabled,
  placeholder,
  options,
}: SelectProps) {
  return (
    <div className="relative">
      <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none z-10">
        {icon}
      </div>
      <select
        value={value}
        onChange={onChange}
        disabled={disabled}
        className="w-full appearance-none border border-gray-400 rounded-xl pl-9 pr-9 py-2.5 text-sm text-gray-700 bg-transparent focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent disabled:bg-gray-50 disabled:text-gray-400 disabled:cursor-not-allowed cursor-pointer"
        style={{ WebkitAppearance: "none" }}
      >
        <option value="">{placeholder}</option>
        {options.map((item) => (
          <option key={item.id} value={item.id}>
            {item.name}
          </option>
        ))}
      </select>
      <div className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none">
        <ChevronDownIcon />
      </div>
    </div>
  );
}

export function Home() {
  const data = useLoaderData() as RegionsData;
  const [searchParams, setSearchParams] = useSearchParams();

  const provinceId = searchParams.get("province");
  const regencyId = searchParams.get("regency");
  const districtId = searchParams.get("district");

  const selectedProvince = data.provinces.find(
    (province) => province.id === Number(provinceId),
  );

  const regencies = provinceId
    ? data.regencies.filter(
        (regency) => regency.province_id === Number(provinceId),
      )
    : [];

  const selectedRegency = regencies.find((r) => r.id === Number(regencyId));

  const districts = regencyId
    ? data.districts.filter(
        (district) => district.regency_id === Number(regencyId),
      )
    : [];

  const selectedDistrict = districts.find((d) => d.id === Number(districtId));

  const handleProvinceChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    if (!value) {
      setSearchParams({});
      return;
    }
    setSearchParams({ province: value });
  };

  const handleRegencyChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    if (!value) {
      setSearchParams({ province: provinceId! });
      return;
    }
    setSearchParams({ province: provinceId!, regency: value });
  };

  const handleDistrictChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    if (!value) {
      setSearchParams({
        province: provinceId!,
        regency: regencyId!,
      });
      return;
    }
    setSearchParams({
      province: provinceId!,
      regency: regencyId!,
      district: value,
    });
  };

  const handleReset = () => {
    setSearchParams({});
  };

  return (
    <div className="min-h-screen flex">
      <aside className="flex flex-col border-r border-gray-300 w-64 min-w-64 bg-gray-100 px-6 py-5">
        <div className="flex items-center gap-2 mb-20">
          <div className="flex items-center justify-center rounded-full text-white w-8 h-8 bg-blue-600">
            <GlobeIcon />
          </div>
          <span className="font-bold">Frontend Assessment</span>
        </div>

        <p className="uppercase tracking-widest font-semibold mb-5 text-[10px] text-gray-400">
          Filter Wilayah
        </p>
        <div className="flex flex-col gap-4 mb-10">
          <div className="flex flex-col gap-2">
            <label className="font-semibold uppercase tracking-wide text-xs text-black block">
              Provinsi
            </label>
            <StyledSelect
              icon={<MapIcon />}
              value={provinceId ?? ""}
              onChange={handleProvinceChange}
              placeholder="Pilih Provinsi"
              options={data.provinces}
            />
          </div>

          <div className="flex flex-col gap-2">
            <label className="font-semibold uppercase tracking-wide text-xs text-black block">
              Kota/Kabupaten
            </label>
            <StyledSelect
              icon={<BuildingIcon />}
              value={regencyId ?? ""}
              onChange={handleRegencyChange}
              disabled={!provinceId}
              placeholder="Pilih Kota/Kabupaten"
              options={regencies}
            />
          </div>

          <div className="flex flex-col gap-2">
            <label className="font-semibold uppercase tracking-wide text-xs text-black block">
              Kecamatan
            </label>
            <StyledSelect
              icon={<LocationIcon />}
              value={districtId ?? ""}
              onChange={handleDistrictChange}
              disabled={!regencyId}
              placeholder="Pilih Kecamatan"
              options={districts}
            />
          </div>
        </div>

        <button
          onClick={handleReset}
          className="flex items-center justify-center gap-2 w-full border border-blue-600 rounded-lg py-2.5 text-sm font-medium text-black bg-transparent transition-colors hover:bg-blue-600 hover:text-white cursor-pointer"
        >
          <ResetIcon />
          RESET
        </button>
      </aside>

      <div className="flex flex-col w-full">
        <nav className="flex items-center gap-1 px-12 h-20 bg-white w-full border-b border-gray-300">
          <span className="text-gray-400 text-sm font-semibold">Indonesia</span>

          {selectedProvince && (
            <>
              <ChevronRightIcon />
              <span
                className={`font-semibold ${
                  selectedRegency ? "text-gray-400" : "text-blue-600"
                }`}
              >
                {selectedProvince.name}
              </span>
            </>
          )}

          {selectedRegency && (
            <>
              <ChevronRightIcon />
              <span
                className={`font-semibold ${
                  selectedDistrict ? "text-gray-400" : "text-blue-600 "
                }`}
              >
                {selectedRegency.name}
              </span>
            </>
          )}

          {selectedDistrict && (
            <>
              <ChevronRightIcon />
              <span className="text-blue-600 font-semibold">
                {selectedDistrict.name}
              </span>
            </>
          )}
        </nav>

        <main className="flex flex-col items-center justify-center pt-5 h-[calc(100vh-80px)] bg-gray-100">
          {selectedProvince && (
            <>
              <div className="flex flex-col items-center mb-2">
                <p className="uppercase tracking-[0.12em] mb-3 text-[11px] text-blue-600 font-semibold">
                  Provinsi
                </p>
                <h1 className="font-black text-slate-900 leading-tight text-[clamp(32px,5vw,56px)]">
                  {selectedProvince.name}
                </h1>
              </div>

              {selectedRegency && (
                <div className="flex items-center justify-center my-6 text-gray-300">
                  <ArrowDownIcon />
                </div>
              )}
            </>
          )}

          {selectedRegency && (
            <>
              <div className="flex flex-col items-center mb-2">
                <p className="uppercase tracking-[0.12em] mb-3 text-[11px] text-blue-600 font-semibold">
                  Kota / Kabupaten
                </p>
                <h2 className="font-black text-slate-900 leading-tight text-[clamp(28px,4vw,48px)]">
                  {selectedRegency.name}
                </h2>
              </div>

              {selectedDistrict && (
                <div className="flex items-center justify-center my-6 text-gray-300">
                  <ArrowDownIcon />
                </div>
              )}
            </>
          )}

          {selectedDistrict && (
            <div className="flex flex-col items-center">
              <p className="uppercase tracking-[0.12em] mb-3 text-[11px] text-blue-600 font-semibold">
                Kecamatan
              </p>
              <h3 className="font-black text-slate-900 leading-tight text-[clamp(24px,3.5vw,44px)]">
                {selectedDistrict.name}
              </h3>
            </div>
          )}

          {!selectedProvince && (
            <div className="flex flex-col items-center justify-center mt-20 text-gray-400">
              <GlobeIcon />
              <p className="mt-4 text-base font-medium text-gray-600">
                Pilih provinsi untuk memulai
              </p>
              <p className="mt-1 text-sm text-gray-400">
                Gunakan filter di sebelah kiri untuk memilih wilayah
              </p>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

const router = createBrowserRouter([
  {
    path: "/",
    element: <Home />,
    loader,
  },
]);

ReactDOM.createRoot(document.getElementById("root")!).render(
  <React.StrictMode>
    <RouterProvider router={router} />
  </React.StrictMode>,
);
